import React, { useEffect } from "react";
import { useDispatch, useSelector } from "react-redux";
import { useLocation, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";
import * as yup from "yup";
import { useFormik } from "formik";
import { Button } from "antd";
import {
  Palette,
  Save,
  ArrowLeft,
  ChevronRight,
  Droplets,
  ShieldCheck,
} from "lucide-react";
import {
  createColor,
  getAColor,
  resetState,
  updateAColor,
} from "../features/color/colorSlice";

let schema = yup.object().shape({
  title: yup.string().required("Color is Required"),
});

const Addcolor = () => {
  const dispatch = useDispatch();
  const location = useLocation();
  const getColorId = location.pathname.split("/")[3];
  const navigate = useNavigate();
  const newColor = useSelector((state) => state.color);
  const {
    isSuccess,
    isError,
    isLoading,
    createdColor,
    colorName,
    updatedColor,
  } = newColor;

  useEffect(() => {
    if (getColorId !== undefined) {
      dispatch(getAColor(getColorId));
    } else {
      dispatch(resetState());
    }
  }, [getColorId]);

  useEffect(() => {
    if (isSuccess && createdColor) {
      toast.success("Color Added Successfully!");
    }
    if (isSuccess && updatedColor) {
      toast.success("Color Updated Successfully!");
      navigate("../list-color");
    }
    if (isError) {
      toast.error("Something Went Wrong!");
    }
  }, [isSuccess, isError, isLoading]);

  const formik = useFormik({
    enableReinitialize: true,
    initialValues: {
      title: colorName || "",
    },
    validationSchema: schema,
    onSubmit: (values) => {
      if (getColorId !== undefined) {
        const data = { id: getColorId, colorData: values };
        dispatch(updateAColor(data));
        dispatch(resetState());
      } else {
        dispatch(createColor(values));
        formik.resetForm();
        setTimeout(() => {
          dispatch(resetState());
        }, 300);
      }
    },
  });

  // Check if input looks like a hex color
  const isHexColor = /^#([0-9A-Fa-f]{3}){1,2}$/.test(formik.values.title);

  return (
    <div className="space-y-12 animate-in fade-in slide-in-from-bottom-8 duration-1000">
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-8 bg-white/40 p-1 rounded-[32px] border border-white/60">
        <div className="pl-8 py-6">
          <div className="flex items-center gap-3 mb-2">
            <div className="w-10 h-10 bg-[#257CB7] rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-500/20">
              <Palette size={20} />
            </div>
            <h1 className="text-4xl font-black text-slate-900 tracking-tighter">
              {getColorId !== undefined ? "Update" : "Add"} Color
            </h1>
          </div>
          <div className="flex items-center gap-4">
            <span className="flex items-center gap-2 text-[10px] font-black text-blue-600 bg-blue-50 border border-blue-100 px-3 py-1 rounded-full uppercase tracking-widest shadow-sm">
              <ShieldCheck size={12} /> Product Attributes
            </span>
          </div>
        </div>
        <div className="flex items-center gap-3 pr-4">
          <Button
            onClick={() => navigate(-1)}
            icon={<ArrowLeft size={16} />}
            className="rounded-2xl h-11 border-slate-200 text-slate-400 font-black text-[10px] uppercase tracking-widest"
          >
            Go Back
          </Button>
        </div>
      </div>

      <div className="max-w-2xl">
        <div className="enterprise-card bg-white p-2 border-none shadow-2xl shadow-slate-200/40">
          <div className="flex items-center gap-4 px-10 py-8 border-b border-slate-50">
            <div className="p-3 bg-slate-50 rounded-2xl border border-slate-100">
              <Droplets size={22} className="text-slate-400" />
            </div>
            <div>
              <h3 className="text-sm font-black text-slate-900 uppercase tracking-widest">
                Color Details
              </h3>
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest mt-1">
                Configure color attributes
              </p>
            </div>
          </div>
          <form onSubmit={formik.handleSubmit} className="p-10 space-y-8">
            <div className="space-y-3">
              <label className="text-[10px] font-black uppercase text-slate-400 tracking-widest flex items-center gap-2">
                <ChevronRight size={12} /> Color Value
              </label>
              <div className="flex items-center gap-4">
                <input
                  type="color"
                  value={isHexColor ? formik.values.title : "#257CB7"}
                  onChange={(e) =>
                    formik.setFieldValue("title", e.target.value)
                  }
                  className="w-16 h-14 rounded-2xl border border-slate-100 cursor-pointer p-1 bg-white"
                />
                <input
                  type="text"
                  placeholder="Enter color (e.g. #257CB7)"
                  onChange={formik.handleChange("title")}
                  onBlur={formik.handleBlur("title")}
                  value={formik.values.title}
                  className="flex-1 px-6 py-4 bg-slate-50/50 border border-slate-100 rounded-2xl focus:outline-none focus:ring-2 focus:ring-[#257CB7] focus:border-transparent transition-all duration-300 font-bold text-slate-900 placeholder-slate-300"
                />
              </div>
              {isHexColor && (
                <div className="flex items-center gap-3 mt-2">
                  <div
                    className="w-12 h-12 rounded-2xl border-2 border-white shadow-lg"
                    style={{ backgroundColor: formik.values.title }}
                  />
                  <span className="text-[10px] font-black uppercase text-slate-400 tracking-widest">
                    Preview: {formik.values.title}
                  </span>
                </div>
              )}
              {formik.touched.title && formik.errors.title && (
                <p className="text-rose-500 text-[10px] uppercase font-black tracking-widest pl-4">
                  {formik.errors.title}
                </p>
              )}
            </div>
            <Button
              type="primary"
              htmlType="submit"
              loading={isLoading}
              size="large"
              icon={<Save size={16} />}
              className="bg-[#257CB7] rounded-2xl h-14 font-black text-[10px] uppercase tracking-widest shadow-xl shadow-blue-500/20 border-none hover:translate-y-[-2px] transition-all w-full flex items-center justify-center gap-3"
            >
              {getColorId !== undefined ? "Update" : "Register"} Color
            </Button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default Addcolor;
